    try:
        a = float(state['kv'].get('final_amount', 'x'))
        g = float(state['kv'].get('gain', 'x'))
    except Exception: return (False, 'D1_missing_or_nan')
    if abs(a - 1389.15) > 0.01: return (False, 'D2_amount_wrong')
    return (abs(g - 189.15) < 0.01, 'D3_gain_wrong')
